class Solution:
    def specialGrid(self, n):
        def build(k):
            if k == 0:
                return [[0]]
            sub = build(k - 1)
            h = len(sub)
            block = h * h
            tr = sub
            br = [[v + block for v in row] for row in sub]
            bl = [[v + 2 * block for v in row] for row in sub]
            tl = [[v + 3 * block for v in row] for row in sub]
            top = [tl[i] + tr[i] for i in range(h)]
            bottom = [bl[i] + br[i] for i in range(h)]
            return top + bottom
        return build(n)

solutions.javascript:
var specialGrid = function(n) {
    function build(k) {
        if (k === 0) return [[0]];
        const sub = build(k - 1);
        const h = sub.length;
        const block = h * h;
        const add = (g, d) => g.map(row => row.map(v => v + d));
        const tr = sub;
        const br = add(sub, block);
        const bl = add(sub, 2 * block);
        const tl = add(sub, 3 * block);
        const res = [];
        for (let i = 0; i < h; i++) res.push(tl[i].concat(tr[i]));
        for (let i = 0; i < h; i++) res.push(bl[i].concat(br[i]));
        return res;
    }
    return build(n);
};
